import { useEffect, useMemo, useRef, useState } from "react";

// Define los colores para fácil acceso
const navy = '#072d42';
const beige = '#F4E9D7';

export default function Index() {
  const sections = useMemo(
    () => [
      {
        id: "objective",
        title: "Objective",
        icon: "📊",
        body: (
          <p className="leading-relaxed">
            Orbis Empresarial preserves, organizes, and showcases the corporate heritage of Bolivian
            companies with more than 40 years of trajectory. We digitize archives, certify milestones,
            and curate living narratives that honor legacy while inspiring the next generation of leaders.
          </p>
        ),
      },
      {
        id: "mission",
        title: "Mission",
        icon: "🎯",
        body: (
          <p className="leading-relaxed">
            To protect the memory of Bolivian enterprise through rigorous documentation, thoughtful
            storytelling, and timeless design—making each company's journey accessible, verifiable, and
            beautifully preserved for the future.
          </p>
        ),
      },
      {
        id: "vision",
        title: "Vision",
        icon: "🔭",
        body: (
          <p className="leading-relaxed">
            A prestigious national archive where the history of business excellence is treasured—
            a reference for researchers, entrepreneurs, and families that elevates the legacy of
            Bolivian industry on the world stage.
          </p>
        ),
      },
      {
        id: "origin",
        title: "Origin",
        icon: "🌱",
        body: (
          <p className="leading-relaxed">
            Born from a commitment to cultural memory, Orbis Empresarial emerged when historians,
            archivists, and innovators united around a single idea: if we don't document our
            enterprises today, tomorrow's generations will inherit silence where there should be legacy.
          </p>
        ),
      },
      {
        id: "how",
        title: "How it started",
        icon: "⏳",
        body: (
          <div className="w-full">
            <div className="relative overflow-x-auto md:overflow-visible px-2 py-6">
              <div
                className="absolute left-6 right-6 md:left-8 md:right-8 top-1/2 -translate-y-1/2 h-[2px] rounded-full"
                style={{ background: `linear-gradient(to right, ${beige}, ${navy}80, ${beige})` }}
              />
              <ol className="relative z-10 flex min-w-[640px] md:min-w-0 items-start gap-10 md:gap-12 lg:gap-16 px-4 md:px-8 snap-x">
                {[
                  { year: "1980s", text: "Foundational archives collected across departments.", icon: "📚" },
                  { year: "1990s", text: "First private–public preservation partnerships.", icon: "🤝" },
                  { year: "2000s", text: "Digitization program and certification standards.", icon: "💾" },
                  { year: "2010s", text: "Interactive exhibits and institutional expansion.", icon: "🚀" },
                  { year: "Today", text: "A living platform connecting legacy with innovation.", icon: "🌐" },
                ].map((m) => (
                  <li key={m.year} className="snap-center min-w-[160px]">
                    <div className="flex flex-col items-center text-center gap-3">
                      <div className="relative">
                        <div className="w-12 h-12 rounded-full flex items-center justify-center text-lg mb-2 transition-transform hover:scale-110" 
                             style={{ backgroundColor: `${navy}15`, border: `1px solid ${navy}30` }}>
                          {m.icon}
                        </div>
                        <span className="absolute -bottom-1 -right-1 w-5 h-5 rounded-full flex items-center justify-center text-xs" 
                              style={{ backgroundColor: navy, color: beige }}>
                          ✓
                        </span>
                      </div>
                      <div className="text-sm font-medium tracking-wide">
                        <span className="font-serif text-xl block mb-1" style={{color: navy}}>{m.year}</span>
                        <span className="block max-w-[16rem] text-sm leading-tight" style={{ color: navy, opacity: 0.8 }}>{m.text}</span>
                      </div>
                    </div>
                  </li>
                ))}
              </ol>
            </div>
          </div>
        ),
      },
    ],
    [],
  );

  const [active, setActive] = useState(sections[0].id);
  const [visible, setVisible] = useState({});
  const [sidebarHover, setSidebarHover] = useState(false);
  const refs = useRef({});

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        let best = { id: active, ratio: 0 };
        entries.forEach((entry) => {
          const id = entry.target.id;
          if (entry.isIntersecting) {
            setVisible((prev) => ({ ...prev, [id]: true }));
          }
          if (entry.intersectionRatio > best.ratio) {
            best = { id, ratio: entry.intersectionRatio };
          }
        });
        if (best.id) setActive(best.id);
      },
      { root: null, threshold: [0.25, 0.5, 0.75], rootMargin: "-20% 0px -40% 0px" },
    );

    sections.forEach((s) => {
      const el = refs.current[s.id];
      if (el) observer.observe(el);
    });
    return () => observer.disconnect();
  }, []);

  const scrollTo = (id) => {
    const el = refs.current[id];
    if (!el) return;
    
    const elementPosition = el.getBoundingClientRect().top + window.pageYOffset;
    const offsetPosition = elementPosition - 100;
    
    window.scrollTo({
      top: offsetPosition,
      behavior: "smooth"
    });
    setActive(id);
  };

  return (
    <div style={{ backgroundColor: beige, color: navy, minHeight: '100vh' }}>
      <main className="mx-auto max-w-[1400px] px-4 sm:px-6 lg:px-10 py-6 sm:py-10">
        {/* Header elegante */}
        <div className="text-center mb-16 md:mb-20">
          <div className="inline-flex items-center justify-center w-20 h-20 rounded-full mb-6" 
               style={{ backgroundColor: `${navy}15`, border: `1px solid ${navy}20` }}>
            <span className="text-3xl" style={{ color: navy }}>OE</span>
          </div>
          <h1 className="font-serif text-4xl md:text-5xl lg:text-6xl font-light tracking-tight mb-4" style={{ color: navy }}>
            Orbis Empresarial
          </h1>
          <div className="h-0.5 w-32 mx-auto rounded-full mb-6" style={{ backgroundColor: `${navy}40` }}></div>
          <p className="max-w-3xl mx-auto text-lg md:text-xl font-light leading-relaxed" style={{ color: navy, opacity: 0.9 }}>
            Observing the living history of Bolivian companies <span className="italic">40 years strong</span>
          </p>
        </div>

        <div className="grid md:grid-cols-[280px_1fr] gap-8 lg:gap-12">
          {/* Sidebar elegante y dinámico */}
          <aside 
            className="hidden md:flex sticky top-8 h-fit flex-col"
            onMouseEnter={() => setSidebarHover(true)}
            onMouseLeave={() => setSidebarHover(false)}
          >
            <div 
              className="rounded-2xl p-6 transition-all duration-500 ease-out"
              style={{ 
                backgroundColor: sidebarHover ? `${navy}08` : `${navy}05`,
                border: `1px solid ${sidebarHover ? `${navy}20` : `${navy}15`}`,
                boxShadow: sidebarHover ? `0 10px 40px ${navy}15` : `0 5px 20px ${navy}08`,
                backdropFilter: 'blur(10px)'
              }}
            >
              <div className="flex items-center gap-3 mb-6">
                <div className="w-3 h-3 rounded-full animate-pulse" style={{ backgroundColor: navy }}></div>
                <h3 className="font-serif text-xl font-light uppercase tracking-widest" style={{ color: navy }}>
                  Navegación
                </h3>
              </div>
              
              <nav className="flex flex-col gap-1">
                {sections.map((s) => (
                  <button
                    key={s.id}
                    onClick={() => scrollTo(s.id)}
                    className="group text-left p-3 rounded-lg transition-all duration-300 ease-out flex items-center gap-4"
                    style={{ 
                      backgroundColor: active === s.id ? `${navy}15` : 'transparent',
                      border: active === s.id ? `1px solid ${navy}30` : `1px solid transparent`,
                      transform: active === s.id ? 'translateX(4px)' : 'translateX(0)'
                    }}
                  >
                    <div 
                      className="w-8 h-8 rounded-full flex items-center justify-center text-sm transition-all duration-300"
                      style={{ 
                        backgroundColor: active === s.id ? navy : `${navy}10`,
                        color: active === s.id ? beige : navy,
                        transform: active === s.id ? 'scale(1.1)' : 'scale(1)'
                      }}
                    >
                      {s.icon}
                    </div>
                    <div className="flex-1 text-left">
                      <div className="flex items-center justify-between">
                        <span 
                          className="font-light tracking-wide transition-all duration-300"
                          style={{ 
                            color: navy,
                            fontWeight: active === s.id ? '500' : '300',
                            letterSpacing: active === s.id ? '0.05em' : '0.025em'
                          }}
                        >
                          {s.title}
                        </span>
                        <div 
                          className="w-2 h-2 rounded-full transition-all duration-300"
                          style={{ 
                            backgroundColor: active === s.id ? navy : 'transparent',
                            opacity: active === s.id ? 1 : 0
                          }}
                        ></div>
                      </div>
                      <div 
                        className="h-0.5 rounded-full mt-1 transition-all duration-500"
                        style={{ 
                          width: active === s.id ? '100%' : '0%',
                          backgroundColor: navy,
                          opacity: active === s.id ? 0.5 : 0
                        }}
                      ></div>
                    </div>
                  </button>
                ))}
              </nav>

              <div className="mt-8 pt-6 border-t" style={{ borderColor: `${navy}15` }}>
                <p className="text-xs font-light tracking-wide" style={{ color: navy, opacity: 0.7 }}>
                  "Preserving corporate heritage through timeless design"
                </p>
              </div>
            </div>
          </aside>

          {/* Secciones de contenido mejoradas */}
          <section className="flex flex-col gap-12 lg:gap-16">
            {sections.map((s, idx) => (
              <div
                key={s.id}
                id={s.id}
                ref={(el) => (refs.current[s.id] = el)}
                className="scroll-mt-28"
              >
                <div
                  className={`group relative transition-all duration-700 ease-out ${
                    visible[s.id] ? "opacity-100 translate-y-0" : "opacity-0 translate-y-8"
                  }`}
                >
                  {/* Encabezado elegante de sección */}
                  <div className="flex items-center gap-4 mb-6">
                    <div 
                      className="w-12 h-12 rounded-full flex items-center justify-center text-lg transition-all duration-300 group-hover:scale-110"
                      style={{ 
                        backgroundColor: `${navy}10`, 
                        border: `1px solid ${navy}20`,
                        color: navy
                      }}
                    >
                      {s.icon}
                    </div>
                    <div>
                      <h2 
                        className="font-serif text-2xl md:text-3xl font-light tracking-wide transition-all duration-300 group-hover:tracking-widest"
                        style={{ color: navy }}
                      >
                        {s.title}
                      </h2>
                      <div 
                        className="h-0.5 rounded-full mt-2 transition-all duration-500 group-hover:w-full"
                        style={{ 
                          width: '40px',
                          backgroundColor: navy
                        }}
                      ></div>
                    </div>
                  </div>

                  {/* Contenido con diseño elegante */}
                  <div 
                    className="rounded-2xl p-8 transition-all duration-500 hover:shadow-2xl"
                    style={{ 
                      backgroundColor: `${beige}f2`,
                      border: `1px solid ${navy}15`,
                      boxShadow: `0 5px 30px ${navy}08`,
                      backdropFilter: 'blur(10px)'
                    }}
                  >
                    <div 
                      className="prose prose-lg max-w-none leading-relaxed font-light"
                      style={{ color: navy, opacity: 0.95 }}
                    >
                      {s.body}
                    </div>
                  </div>
                </div>

                {/* Separador elegante entre secciones */}
                {idx !== sections.length - 1 && (
                  <div className="mt-12 lg:mt-16 flex justify-center">
                    <div 
                      className="w-16 h-16 rounded-full flex items-center justify-center text-xl transition-transform duration-500 hover:rotate-180"
                      style={{ 
                        backgroundColor: `${navy}08`,
                        border: `1px solid ${navy}15`,
                        color: navy
                      }}
                    >
                      ↓
                    </div>
                  </div>
                )}
              </div>
            ))}
          </section>
        </div>

        {/* Footer elegante */}
        <footer className="mt-20 pt-8 border-t text-center" style={{ borderColor: `${navy}15` }}>
          <p className="text-sm font-light tracking-wide" style={{ color: navy, opacity: 0.7 }}>
            © {new Date().getFullYear()} Orbis Empresarial • Preserving Bolivian corporate heritage since 1980
          </p>
        </footer>
      </main>
    </div>
  );
}
